import React, { useEffect, useState } from 'react';
import api from '../api';

const AppointmentList = () => {
  useEffect(() => {
    api.get('appointments/')
      .then((res: any) => setAppointments(res.data))
      .catch((err: any) => console.error("Error fetching appointments:", err));
  }, []);

  return (
    <div className="overflow-x-auto bg-white rounded-xl shadow-md border border-gray-100">
      <table className="min-w-full divide-y divide-gray-200">
        <thead className="bg-gray-50">
          <tr>
            <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase">ID</th>
            <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase">Schedule</th>
            <th className="px-6 py-4 text-center text-xs font-bold text-gray-500 uppercase">Status</th>
          </tr>
        </thead>
        <tbody className="divide-y divide-gray-100">
          {appointments.map((a: any) => (
            <tr key={a.appointment_id} className="hover:bg-gray-50">
              <td className="px-6 py-4 text-sm font-mono text-blue-600">#{a.appointment_id}</td>
              <td className="px-6 py-4 text-sm text-gray-800">{a.date} - {a.time}</td>
              <td className="px-6 py-4 text-center">
                <span className="px-3 py-1 text-xs font-semibold bg-green-100 text-green-700 rounded-full">
                  Confirmed
                </span>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default AppointmentList;
